def process_csv(filename):
    data = []
    with open(filename, mode='r') as file:
        reader = csv.DictReader(file)
        for row in reader:
            data.append(row)

    average_score = sum(float(row['score']) for row in data) / len(data)
    a_students = [row['name'] for row in data if row['grade'].upper() == 'A']

    return {
        'average_score': float(average_score),
        'a_students': a_students
    }

